import { useState } from 'react'
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog'
import { Input } from '@/components/ui/input'
import { Button } from '@/components/ui/button'
import { Label } from '@/components/ui/label'
import { useRepo } from '@/context/repo.js'
import type { DialogContextProps } from '@/utils/dialogs.js'
import {
  agentTokenStore,
  notifyAgentTokensChanged,
} from './tokens.ts'
import type { AgentToken } from './tokens.ts'

export type AgentTokensDialogMode = 'manage' | 'pair-cli'

export interface AgentTokensDialogProps {
  mode?: AgentTokensDialogMode
}

export function AgentTokensDialog({
  mode = 'manage',
  cancel,
}: DialogContextProps<void> & AgentTokensDialogProps) {
  const repo = useRepo()
  const userId = repo.user.id
  const workspaceId = repo.activeWorkspaceId
  const noWorkspace = !userId || !workspaceId
  const pairing = mode === 'pair-cli'

  return (
    <Dialog open onOpenChange={next => { if (!next) cancel() }}>
      <DialogContent className="max-h-[calc(100vh-2rem)] w-[calc(100vw-2rem)] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>{pairing ? 'Pair agent CLI' : 'Agent runtime tokens'}</DialogTitle>
          <DialogDescription>
            {pairing
              ? 'Generate a token for this workspace, copy it, then paste it into the waiting terminal prompt.'
              : 'Tokens authorize a local agent process to drive this workspace as you. Stored on this device only; each token is shown once at mint.'}
          </DialogDescription>
        </DialogHeader>

        {noWorkspace ? (
          <p className="text-sm text-destructive">
            Open a workspace before minting agent tokens.
          </p>
        ) : (
          // Body is a separate component so its useState initializers
          // run fresh each time the dialog opens (Radix unmounts the
          // content on close). That avoids a setState-in-effect pattern
          // for "reset transient form state when the dialog opens".
          <AgentTokensDialogBody
            userId={userId}
            workspaceId={workspaceId}
            pairing={pairing}
          />
        )}
      </DialogContent>
    </Dialog>
  )
}

function AgentTokensDialogBody({
  userId,
  workspaceId,
  pairing,
}: {
  userId: string
  workspaceId: string
  pairing: boolean
}) {
  const [tokens, setTokens] = useState<AgentToken[]>(
    () => agentTokenStore.list(userId, workspaceId),
  )
  const [label, setLabel] = useState(pairing ? 'agent-cli' : '')
  const [readOnly, setReadOnly] = useState(false)
  const [justMinted, setJustMinted] = useState<AgentToken | null>(null)
  const [copyState, setCopyState] = useState<'idle' | 'copied'>('idle')

  const refresh = () => setTokens(agentTokenStore.list(userId, workspaceId))

  const mint = () => {
    const token = agentTokenStore.create(userId, workspaceId, label, readOnly ? 'read-only' : 'read-write')
    notifyAgentTokensChanged()
    setJustMinted(token)
    setCopyState('idle')
    setLabel('')
    refresh()
  }

  const revoke = (token: string) => {
    agentTokenStore.revoke(userId, workspaceId, token)
    notifyAgentTokensChanged()
    if (justMinted?.token === token) setJustMinted(null)
    refresh()
  }

  const copy = async (text: string) => {
    try {
      await navigator.clipboard.writeText(text)
      setCopyState('copied')
      window.setTimeout(() => setCopyState('idle'), 1500)
    } catch (error) {
      console.error('Clipboard write failed', error)
    }
  }

  return (
    <>
      <div className="space-y-2">
        <Label htmlFor="agent-token-label">New token label</Label>
        {pairing && (
          <p className="text-xs text-muted-foreground">
            Use a label that identifies this terminal session.
          </p>
        )}
        <div className="flex min-w-0 gap-2">
          <Input
            id="agent-token-label"
            className="min-w-0 flex-1"
            placeholder="e.g. claude-cli"
            value={label}
            onChange={(e) => setLabel(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter') mint() }}
          />
          <Button type="button" className="shrink-0" onClick={mint}>
            Generate
          </Button>
        </div>
        <label className="flex items-center gap-2 text-sm">
          <input
            type="checkbox"
            className="size-4"
            checked={readOnly}
            onChange={(e) => setReadOnly(e.target.checked)}
          />
          Read-only
        </label>
      </div>

      {justMinted && (
        <div className="min-w-0 rounded-md border bg-muted/40 p-3 space-y-2">
          <p className="text-xs font-medium text-muted-foreground">
            Copy now. This is the only time the secret is shown.
          </p>
          <div className="flex min-w-0 items-center gap-2">
            <code className="min-w-0 flex-1 truncate text-xs font-mono">{justMinted.token}</code>
            <Button
              type="button"
              variant="secondary"
              size="sm"
              className="shrink-0"
              onClick={() => copy(justMinted.token)}
            >
              {copyState === 'copied' ? 'Copied' : 'Copy'}
            </Button>
          </div>
          <p className="min-w-0 text-xs text-muted-foreground">
            {pairing ? (
              'Paste this token into the waiting terminal prompt to finish pairing.'
            ) : (
              <>
                Run{' '}
                <code className="break-all whitespace-normal">
                  pnpm agent connect {justMinted.token}
                </code>{' '}
                to register it with the CLI.
              </>
            )}
          </p>
        </div>
      )}

      <div className="space-y-2">
        <Label>Existing tokens</Label>
        {tokens.length === 0 ? (
          <p className="text-sm text-muted-foreground">No tokens yet.</p>
        ) : (
          <ul className="space-y-1.5">
            {tokens.map((t) => (
              <li
                key={t.token}
                className="flex items-center justify-between rounded border p-2 text-sm"
              >
                <div className="min-w-0">
                  <div className="font-medium truncate">{t.label}</div>
                  <div className="text-xs text-muted-foreground">
                    {(t.scope ?? 'read-write') === 'read-only' ? 'read-only' : 'read/write'}
                    {' · '}
                    created {new Date(t.createdAt).toLocaleString()}
                    {t.lastSeenAt
                      ? ` · last seen ${new Date(t.lastSeenAt).toLocaleString()}`
                      : ''}
                  </div>
                </div>
                <Button
                  type="button"
                  variant="destructive"
                  size="sm"
                  onClick={() => revoke(t.token)}
                >
                  Revoke
                </Button>
              </li>
            ))}
          </ul>
        )}
      </div>
    </>
  )
}
